import{_ as e,o as a,c as l,ag as n}from"./chunks/framework.C1fqlEKx.js";const u=JSON.parse('{"title":"관리자 도입 가이드","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin.md","filePath":"guide/admin.md","lastUpdated":1773586478000}'),r={name:"guide/admin.md"};function s(i,t,d,o,g,h){return a(),l("div",null,[...t[0]||(t[0]=[n(`<h1 id="관리자-도입-가이드" tabindex="-1">관리자 도입 가이드 <a class="header-anchor" href="#관리자-도입-가이드" aria-label="Permalink to &quot;관리자 도입 가이드&quot;">​</a></h1><blockquote><p>팀 리더, IT 관리자, 의사결정자를 위한 Claude Desktop Cowork 도입 전략 가이드입니다. ROI 분석부터 롤아웃 계획, 성과 측정까지 한 번에 정리했습니다.</p></blockquote><h2 id="왜-cowork를-도입해야-하나" tabindex="-1">왜 Cowork를 도입해야 하나? <a class="header-anchor" href="#왜-cowork를-도입해야-하나" aria-label="Permalink to &quot;왜 Cowork를 도입해야 하나?&quot;">​</a></h2><h3 id="시간-절약-효과" tabindex="-1">시간 절약 효과 <a class="header-anchor" href="#시간-절약-효과" aria-label="Permalink to &quot;시간 절약 효과&quot;">​</a></h3><p>Cowork 도입 기업들의 평균 업무 시간 단축 수치입니다.</p><table tabindex="0"><thead><tr><th>업무 유형</th><th style="text-align:center;">기존 소요 시간</th><th style="text-align:center;">Cowork 활용 시</th><th style="text-align:center;">단축률</th></tr></thead><tbody><tr><td>이메일 작성</td><td style="text-align:center;">15분</td><td style="text-align:center;">4분</td><td style="text-align:center;"><strong>약 70%</strong></td></tr><tr><td>주간/월간 보고서</td><td style="text-align:center;">2시간</td><td style="text-align:center;">50분</td><td style="text-align:center;"><strong>약 60%</strong></td></tr><tr><td>회의록 정리</td><td style="text-align:center;">40분</td><td style="text-align:center;">10분</td><td style="text-align:center;"><strong>약 75%</strong></td></tr><tr><td>데이터 요약·분석</td><td style="text-align:center;">1시간 30분</td><td style="text-align:center;">30분</td><td style="text-align:center;"><strong>약 65%</strong></td></tr><tr><td>제안서·기획서 초안</td><td style="text-align:center;">3시간</td><td style="text-align:center;">1시간</td><td style="text-align:center;"><strong>약 65%</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">1인당 하루 평균 45분 절약</p><p>직원 50명 기준 한 달(22일) 약 <strong>825시간</strong>, 연간 약 <strong>9,900시간</strong>을 절약할 수 있습니다. 이를 인건비로 환산하면 연간 수억 원 규모의 효과입니다.</p></div><h3 id="품질-향상" tabindex="-1">품질 향상 <a class="header-anchor" href="#품질-향상" aria-label="Permalink to &quot;품질 향상&quot;">​</a></h3><ul><li><strong>일관성 확보</strong> — 팀 전체가 동일한 톤·양식으로 문서를 작성하여 브랜드 일관성 유지</li><li><strong>오탈자·맞춤법 감소</strong> — AI가 실시간으로 교정하여 대외 문서 품질 향상</li><li><strong>논리 구조 개선</strong> — 보고서·기획서의 흐름을 검토받아 설득력 있는 문서 완성</li><li><strong>다국어 대응</strong> — 영문 이메일, 일문 자료 등 외국어 업무도 자연스럽게 처리</li></ul><h3 id="직원-만족도" tabindex="-1">직원 만족도 <a class="header-anchor" href="#직원-만족도" aria-label="Permalink to &quot;직원 만족도&quot;">​</a></h3><ul><li>단순 반복 업무 감소로 <strong>핵심 업무 집중도 향상</strong></li><li>&quot;AI 활용 역량&quot;이라는 <strong>새로운 성장 기회</strong> 제공</li><li>야근 감소, 업무 스트레스 완화로 <strong>워라밸 개선</strong></li><li>도입 기업 설문 결과 직원 만족도 평균 <strong>4.2 / 5.0</strong></li></ul><hr><h2 id="플랜-비교" tabindex="-1">플랜 비교 <a class="header-anchor" href="#플랜-비교" aria-label="Permalink to &quot;플랜 비교&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th style="text-align:center;"><strong>Pro</strong></th><th style="text-align:center;"><strong>Team</strong></th><th style="text-align:center;"><strong>Enterprise</strong></th></tr></thead><tbody><tr><td>월 가격 (1인)</td><td style="text-align:center;">$20</td><td style="text-align:center;">$25</td><td style="text-align:center;">별도 문의</td></tr><tr><td>사용량 한도</td><td style="text-align:center;">개인 한도</td><td style="text-align:center;">팀 공유 한도 (더 여유)</td><td style="text-align:center;">맞춤 설정</td></tr><tr><td>모델 접근</td><td style="text-align:center;">Claude Sonnet / Opus</td><td style="text-align:center;">Claude Sonnet / Opus</td><td style="text-align:center;">Claude Sonnet / Opus + 전용 용량</td></tr><tr><td>파일 업로드</td><td style="text-align:center;">O</td><td style="text-align:center;">O</td><td style="text-align:center;">O</td></tr><tr><td>프로젝트 기능</td><td style="text-align:center;">O</td><td style="text-align:center;">O</td><td style="text-align:center;">O</td></tr><tr><td>팀 관리 콘솔</td><td style="text-align:center;">X</td><td style="text-align:center;"><strong>O</strong></td><td style="text-align:center;"><strong>O</strong></td></tr><tr><td>멤버 역할 관리</td><td style="text-align:center;">X</td><td style="text-align:center;">기본</td><td style="text-align:center;">세분화 (관리자/편집자/뷰어)</td></tr><tr><td>SSO (Single Sign-On)</td><td style="text-align:center;">X</td><td style="text-align:center;">X</td><td style="text-align:center;"><strong>O</strong></td></tr><tr><td>감사 로그 (Audit Log)</td><td style="text-align:center;">X</td><td style="text-align:center;">X</td><td style="text-align:center;"><strong>O</strong></td></tr><tr><td>데이터 보존 정책</td><td style="text-align:center;">기본</td><td style="text-align:center;">기본</td><td style="text-align:center;">맞춤 설정</td></tr><tr><td>학습 데이터 사용</td><td style="text-align:center;">비사용 (옵트아웃)</td><td style="text-align:center;"><strong>비사용 (기본)</strong></td><td style="text-align:center;"><strong>비사용 (기본)</strong></td></tr><tr><td>전담 지원</td><td style="text-align:center;">X</td><td style="text-align:center;">우선 지원</td><td style="text-align:center;"><strong>전담 CSM 배정</strong></td></tr><tr><td>SLA 보장</td><td style="text-align:center;">X</td><td style="text-align:center;">X</td><td style="text-align:center;"><strong>O</strong></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">플랜 선택 팁</p><ul><li><strong>5명 이하 소규모 팀</strong> → Pro 각자 구독도 가능하지만, 관리 편의성을 위해 Team 추천</li><li><strong>10명 이상 조직</strong> → Team 필수 (멤버 관리, 비용 정산 일원화)</li><li><strong>보안 규정이 엄격한 기업</strong> → Enterprise (SSO, 감사 로그, SLA 필수)</li></ul></div><hr><h2 id="도입-로드맵" tabindex="-1">도입 로드맵 <a class="header-anchor" href="#도입-로드맵" aria-label="Permalink to &quot;도입 로드맵&quot;">​</a></h2><h3 id="phase-1-파일럿-1-2팀-2주" tabindex="-1">Phase 1: 파일럿 (1~2팀, 2주) <a class="header-anchor" href="#phase-1-파일럿-1-2팀-2주" aria-label="Permalink to &quot;Phase 1: 파일럿 (1~2팀, 2주)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">주차</th><th>활동</th><th>담당</th></tr></thead><tbody><tr><td style="text-align:center;">1주</td><td>파일럿 팀 선정 (IT에 익숙한 팀 + 일반 업무 팀)</td><td>도입 담당자</td></tr><tr><td style="text-align:center;">1주</td><td>Team 플랜 트라이얼 신청, 계정 세팅</td><td>IT 관리자</td></tr><tr><td style="text-align:center;">1주</td><td>파일럿 팀 대상 1시간 교육 실시</td><td>도입 담당자</td></tr><tr><td style="text-align:center;">2주</td><td>일일 업무에 Cowork 적용, 피드백 수집</td><td>파일럿 팀</td></tr><tr><td style="text-align:center;">2주</td><td>사용량·만족도 중간 점검</td><td>도입 담당자</td></tr><tr><td style="text-align:center;">2주</td><td>파일럿 결과 보고서 작성 → 경영진 보고</td><td>도입 담당자</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">파일럿 팀 선정 기준</p><p>문서 작성·이메일 빈도가 높은 팀(마케팅, 영업, HR 등)을 포함하면 효과를 빠르게 체감할 수 있습니다. IT 부서도 반드시 포함하여 보안·인프라 관점에서 사전 검토하세요.</p></div><h3 id="phase-2-확대-전체-부서-1개월" tabindex="-1">Phase 2: 확대 (전체 부서, 1개월) <a class="header-anchor" href="#phase-2-확대-전체-부서-1개월" aria-label="Permalink to &quot;Phase 2: 확대 (전체 부서, 1개월)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">주차</th><th>활동</th></tr></thead><tbody><tr><td style="text-align:center;">1주</td><td>전사 공지, 계정 일괄 생성</td></tr><tr><td style="text-align:center;">1~2주</td><td>부서별 온보딩 교육 (1시간 × 부서 수)</td></tr><tr><td style="text-align:center;">2~3주</td><td>부서별 활용 사례 공유 세션</td></tr><tr><td style="text-align:center;">3~4주</td><td>사용 현황 모니터링, 미사용자 리마인드</td></tr><tr><td style="text-align:center;">4주</td><td>1차 성과 측정 및 보고</td></tr></tbody></table><h3 id="phase-3-정착-지속" tabindex="-1">Phase 3: 정착 (지속) <a class="header-anchor" href="#phase-3-정착-지속" aria-label="Permalink to &quot;Phase 3: 정착 (지속)&quot;">​</a></h3><ul><li><strong>사내 AI 사용 가이드라인</strong> 수립 및 배포</li><li><strong>Cowork 챔피언</strong> 제도 운영 (부서별 1명, 활용 전파자 역할)</li><li>월 1회 <strong>Best Practice 공유회</strong> 개최</li><li>분기별 <strong>사용 현황 리포트</strong> 발행</li><li>신입사원 온보딩 프로그램에 Cowork 교육 포함</li></ul><hr><h2 id="팀-온보딩-체크리스트" tabindex="-1">팀 온보딩 체크리스트 <a class="header-anchor" href="#팀-온보딩-체크리스트" aria-label="Permalink to &quot;팀 온보딩 체크리스트&quot;">​</a></h2><p>관리자가 팀 온보딩 시 확인해야 할 항목입니다.</p><h3 id="사전-준비" tabindex="-1">사전 준비 <a class="header-anchor" href="#사전-준비" aria-label="Permalink to &quot;사전 준비&quot;">​</a></h3><ul><li>[ ] Team/Enterprise 플랜 결제 완료</li><li>[ ] 팀원 이메일 목록 정리 (초대용)</li><li>[ ] 관리 콘솔에서 팀 워크스페이스 생성</li><li>[ ] 멤버 역할 설정 (관리자 / 일반 사용자)</li><li>[ ] 사내 보안팀과 데이터 처리 정책 협의 완료</li></ul><h3 id="계정-세팅" tabindex="-1">계정 세팅 <a class="header-anchor" href="#계정-세팅" aria-label="Permalink to &quot;계정 세팅&quot;">​</a></h3><ul><li>[ ] 팀원 전원 초대 메일 발송</li><li>[ ] 전원 로그인 확인</li><li>[ ] SSO 연동 (Enterprise인 경우)</li><li>[ ] 공용 프로젝트 생성 (팀 프롬프트 템플릿 공유용)</li></ul><h3 id="교육·안내" tabindex="-1">교육·안내 <a class="header-anchor" href="#교육·안내" aria-label="Permalink to &quot;교육·안내&quot;">​</a></h3><ul><li>[ ] 온보딩 교육 일정 공지</li><li>[ ] 이 가이드 사이트 URL 공유</li><li>[ ] 사내 AI 사용 가이드라인 배포</li><li>[ ] 질문·피드백 채널 개설 (Slack/Teams 채널 등)</li><li>[ ] 파일럿 기간 중 주 1회 체크인 미팅 설정</li></ul><h3 id="운영·모니터링" tabindex="-1">운영·모니터링 <a class="header-anchor" href="#운영·모니터링" aria-label="Permalink to &quot;운영·모니터링&quot;">​</a></h3><ul><li>[ ] 주간 사용량 리포트 확인 루틴 설정</li><li>[ ] 미사용자 파악 및 개별 안내</li><li>[ ] 월 1회 만족도 설문 실시</li><li>[ ] 분기별 성과 보고서 작성</li></ul><hr><h2 id="교육-프로그램-제안" tabindex="-1">교육 프로그램 제안 <a class="header-anchor" href="#교육-프로그램-제안" aria-label="Permalink to &quot;교육 프로그램 제안&quot;">​</a></h2><h3 id="_1시간-팀-교육-커리큘럼" tabindex="-1">1시간 팀 교육 커리큘럼 <a class="header-anchor" href="#_1시간-팀-교육-커리큘럼" aria-label="Permalink to &quot;1시간 팀 교육 커리큘럼&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">시간</th><th>내용</th><th style="text-align:center;">형식</th></tr></thead><tbody><tr><td style="text-align:center;">0:00 ~ 0:05</td><td><strong>인트로</strong> — 왜 AI 협업 도구가 필요한가, 도입 배경 설명</td><td style="text-align:center;">강의</td></tr><tr><td style="text-align:center;">0:05 ~ 0:10</td><td><strong>Cowork 소개</strong> — 무엇이고, 무엇을 할 수 있는지</td><td style="text-align:center;">강의</td></tr><tr><td style="text-align:center;">0:10 ~ 0:20</td><td><strong>라이브 데모</strong> — 이메일 작성, 보고서 요약, 데이터 분석 실연</td><td style="text-align:center;">시연</td></tr><tr><td style="text-align:center;">0:20 ~ 0:35</td><td><strong>실습 시간</strong> — 참가자 직접 체험 (준비된 실습 시나리오 3개)</td><td style="text-align:center;">실습</td></tr><tr><td style="text-align:center;">0:35 ~ 0:45</td><td><strong>프롬프트 작성법</strong> — 좋은 질문 vs 나쁜 질문, 핵심 원칙 5가지</td><td style="text-align:center;">강의</td></tr><tr><td style="text-align:center;">0:45 ~ 0:50</td><td><strong>보안·주의사항</strong> — 입력하면 안 되는 정보, 팩트체크 필수 등</td><td style="text-align:center;">강의</td></tr><tr><td style="text-align:center;">0:50 ~ 1:00</td><td><strong>Q&amp;A 및 마무리</strong> — 질문 응답, 가이드 사이트 안내, 피드백 채널 공유</td><td style="text-align:center;">토론</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">교육 효과를 높이는 방법</p><ul><li>실습 시나리오는 <strong>해당 부서의 실제 업무</strong>로 준비하세요 (마케팅팀이면 SNS 캡션 작성, 영업팀이면 제안서 초안 등)</li><li>교육 전 참가자에게 &quot;AI에게 시켜보고 싶은 업무 1가지&quot;를 미리 받아두면 실습이 더 풍성해집니다</li><li>교육 후 1주일간 &quot;오늘의 Cowork 활용기&quot;를 팀 채널에 공유하는 미션을 주면 정착률이 올라갑니다</li></ul></div><h3 id="실습-시나리오-예시" tabindex="-1">실습 시나리오 예시 <a class="header-anchor" href="#실습-시나리오-예시" aria-label="Permalink to &quot;실습 시나리오 예시&quot;">​</a></h3><p><strong>시나리오 1: 이메일 작성 (5분)</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 상황으로 거래처에 보낼 이메일을 써줘:</span></span>
<span class="line"><span>- 받는 사람: 한국물산 김 과장님</span></span>
<span class="line"><span>- 목적: 다음 주 미팅 일정 조율</span></span>
<span class="line"><span>- 희망 일시: 3/24(화) 또는 3/25(수) 오후</span></span>
<span class="line"><span>- 톤: 정중하고 간결하게</span></span></code></pre></div><p><strong>시나리오 2: 보고서 요약 (5분)</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 텍스트를 경영진 보고용으로 요약해줘:</span></span>
<span class="line"><span>- 핵심 숫자 위주로</span></span>
<span class="line"><span>- 3줄 이내</span></span>
<span class="line"><span>- &quot;그래서 뭘 해야 하는지&quot; 액션 아이템 포함</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[연습용 텍스트 붙여넣기]</span></span></code></pre></div><p><strong>시나리오 3: 데이터 정리 (5분)</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 표 데이터를 분석해줘:</span></span>
<span class="line"><span>1. 부서별 합계 정리</span></span>
<span class="line"><span>2. 전월 대비 증감률</span></span>
<span class="line"><span>3. 특이사항 요약</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[연습용 표 데이터 붙여넣기]</span></span></code></pre></div><hr><h2 id="성과-측정-방법" tabindex="-1">성과 측정 방법 <a class="header-anchor" href="#성과-측정-방법" aria-label="Permalink to &quot;성과 측정 방법&quot;">​</a></h2><h3 id="핵심-지표-kpi" tabindex="-1">핵심 지표 (KPI) <a class="header-anchor" href="#핵심-지표-kpi" aria-label="Permalink to &quot;핵심 지표 (KPI)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>지표</th><th>측정 방법</th><th style="text-align:center;">목표 (3개월)</th></tr></thead><tbody><tr><td><strong>업무 시간 단축률</strong></td><td>도입 전후 주요 업무 소요 시간 비교 (자기 보고)</td><td style="text-align:center;">40% 이상</td></tr><tr><td><strong>일일 활성 사용률</strong></td><td>관리 콘솔 → 일별 로그인 사용자 수 / 전체 인원</td><td style="text-align:center;">70% 이상</td></tr><tr><td><strong>주간 대화 수</strong></td><td>관리 콘솔 → 주간 총 대화 세션 수</td><td style="text-align:center;">인당 15회 이상</td></tr><tr><td><strong>문서 작성 생산성</strong></td><td>동일 기간 작성된 문서 건수 비교</td><td style="text-align:center;">30% 증가</td></tr><tr><td><strong>사용자 만족도</strong></td><td>월간 설문 (5점 척도)</td><td style="text-align:center;">4.0 이상</td></tr><tr><td><strong>오류·수정 횟수</strong></td><td>문서 반려·수정 요청 건수</td><td style="text-align:center;">20% 감소</td></tr></tbody></table><h3 id="측정-일정" tabindex="-1">측정 일정 <a class="header-anchor" href="#측정-일정" aria-label="Permalink to &quot;측정 일정&quot;">​</a></h3><table tabindex="0"><thead><tr><th>시점</th><th>활동</th></tr></thead><tbody><tr><td>도입 전 (Baseline)</td><td>주요 업무 소요 시간 측정, 현재 만족도 설문</td></tr><tr><td>2주 후 (파일럿 종료)</td><td>파일럿 팀 성과 측정, 피드백 인터뷰</td></tr><tr><td>1개월 후</td><td>전사 1차 성과 측정, 사용 현황 리포트</td></tr><tr><td>3개월 후</td><td>정식 ROI 분석 보고서 작성</td></tr><tr><td>이후 분기별</td><td>정기 성과 리포트</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">측정 템플릿</p><p>설문은 간단하게 5문항 이내로 구성하세요:</p><ol><li>Cowork를 얼마나 자주 사용하나요? (매일/주 3-4회/주 1-2회/거의 안 씀)</li><li>가장 많이 사용하는 업무는? (복수 선택)</li><li>업무 시간이 줄었다고 느끼나요? (5점 척도)</li><li>업무 품질이 향상되었다고 느끼나요? (5점 척도)</li><li>개선 의견이 있다면? (주관식)</li></ol></div><hr><h2 id="자주-묻는-관리자-질문" tabindex="-1">자주 묻는 관리자 질문 <a class="header-anchor" href="#자주-묻는-관리자-질문" aria-label="Permalink to &quot;자주 묻는 관리자 질문&quot;">​</a></h2><h3 id="직원들이-안-쓰려고-하면-어떻게-하나요" tabindex="-1">&quot;직원들이 안 쓰려고 하면 어떻게 하나요?&quot; <a class="header-anchor" href="#직원들이-안-쓰려고-하면-어떻게-하나요" aria-label="Permalink to &quot;&quot;직원들이 안 쓰려고 하면 어떻게 하나요?&quot;&quot;">​</a></h3><p>가장 흔한 고민입니다. 강제하기보다는 <strong>자연스러운 동기부여</strong>가 핵심입니다.</p><ul><li><strong>Quick Win 보여주기</strong> — 교육 시 &quot;이메일 15분 → 3분&quot; 같은 극적인 차이를 라이브로 시연</li><li><strong>챔피언 활용</strong> — 팀 내 얼리어답터가 활용 사례를 자발적으로 공유하도록 유도</li><li><strong>작은 성공 경험</strong> — 처음에는 &quot;오늘 이메일 하나만 Cowork로 써보세요&quot; 같은 미니 미션 부여</li><li><strong>경쟁 심리</strong> — 부서별 활용 현황 공유 (순위 아닌, 우수 사례 중심)</li></ul><div class="warning custom-block"><p class="custom-block-title">주의</p><p>&quot;AI 안 쓰면 뒤처진다&quot;는 식의 압박은 역효과를 냅니다. &quot;편한 도구 하나 더 생겼다&quot; 정도의 가벼운 접근이 효과적입니다.</p></div><h3 id="보안-이슈는-없나요" tabindex="-1">&quot;보안 이슈는 없나요?&quot; <a class="header-anchor" href="#보안-이슈는-없나요" aria-label="Permalink to &quot;&quot;보안 이슈는 없나요?&quot;&quot;">​</a></h3><ul><li>Team/Enterprise 플랜은 <strong>입력 데이터가 모델 학습에 사용되지 않습니다</strong> (기본 설정)</li><li>Enterprise 플랜은 <strong>SOC 2 Type II</strong> 인증 준수</li><li><strong>SSO 연동</strong>으로 사내 인증 체계와 통합 가능 (Enterprise)</li><li><strong>감사 로그</strong>로 누가 언제 어떤 대화를 했는지 추적 가능 (Enterprise)</li><li>그래도 <strong>고객 개인정보, 비밀번호, 사내 기밀 문서 원문</strong>은 입력하지 않도록 가이드라인에 명시하세요</li></ul><h3 id="기존-업무-시스템과-충돌하지-않나요" tabindex="-1">&quot;기존 업무 시스템과 충돌하지 않나요?&quot; <a class="header-anchor" href="#기존-업무-시스템과-충돌하지-않나요" aria-label="Permalink to &quot;&quot;기존 업무 시스템과 충돌하지 않나요?&quot;&quot;">​</a></h3><p>Cowork는 <strong>독립적인 데스크탑 앱</strong>이므로 기존 시스템과 충돌하지 않습니다. 별도 서버 설치나 인프라 변경이 필요 없고, 웹 브라우저와 데스크탑 앱만 있으면 됩니다.</p><h3 id="비용-대비-효과가-정말-있나요" tabindex="-1">&quot;비용 대비 효과가 정말 있나요?&quot; <a class="header-anchor" href="#비용-대비-효과가-정말-있나요" aria-label="Permalink to &quot;&quot;비용 대비 효과가 정말 있나요?&quot;&quot;">​</a></h3><p>계산 예시 (직원 50명, Team 플랜 기준):</p><ul><li>월 비용: 50명 × $25 = <strong>$1,250/월</strong> (약 165만 원)</li><li>월 절약 시간: 50명 × 45분/일 × 22일 = <strong>825시간/월</strong></li><li>시급 3만 원 기준 절약 금액: <strong>2,475만 원/월</strong></li><li><strong>ROI: 약 15배</strong></li></ul><h3 id="chatgpt나-다른-ai와-뭐가-다른가요" tabindex="-1">&quot;ChatGPT나 다른 AI와 뭐가 다른가요?&quot; <a class="header-anchor" href="#chatgpt나-다른-ai와-뭐가-다른가요" aria-label="Permalink to &quot;&quot;ChatGPT나 다른 AI와 뭐가 다른가요?&quot;&quot;">​</a></h3><ul><li><strong>팀 관리 기능</strong> — 멤버 관리, 사용량 모니터링, 역할 설정이 가능</li><li><strong>프로젝트 기능</strong> — 팀 공용 프롬프트 템플릿, 지식 베이스 공유</li><li><strong>보안</strong> — 기업용 데이터 보호 정책, 학습 데이터 비사용 기본 적용</li><li><strong>긴 문맥 처리</strong> — 긴 문서, 대량 데이터도 한 번에 처리 가능</li><li><strong>파일 작업</strong> — PDF, Excel, 이미지 등 다양한 파일 직접 분석</li></ul><h3 id="도입에-it-부서-공수가-많이-드나요" tabindex="-1">&quot;도입에 IT 부서 공수가 많이 드나요?&quot; <a class="header-anchor" href="#도입에-it-부서-공수가-많이-드나요" aria-label="Permalink to &quot;&quot;도입에 IT 부서 공수가 많이 드나요?&quot;&quot;">​</a></h3><p>거의 들지 않습니다. 클라우드 SaaS이므로 별도 서버 구축이 불필요합니다.</p><ul><li><strong>Team 플랜</strong>: 관리 콘솔에서 이메일 초대 → 끝 (30분 이내)</li><li><strong>Enterprise 플랜</strong>: SSO 연동 설정이 추가되지만, 가이드 문서가 제공되며 전담 CSM이 지원합니다</li></ul><hr><h2 id="사내-가이드라인-템플릿" tabindex="-1">사내 가이드라인 템플릿 <a class="header-anchor" href="#사내-가이드라인-템플릿" aria-label="Permalink to &quot;사내 가이드라인 템플릿&quot;">​</a></h2><p>아래 템플릿을 회사 상황에 맞게 수정하여 사용하세요.</p><hr><h3 id="📋-회사명-ai-도구-사용-가이드라인" tabindex="-1">📋 [회사명] AI 도구 사용 가이드라인 <a class="header-anchor" href="#📋-회사명-ai-도구-사용-가이드라인" aria-label="Permalink to &quot;📋 [회사명] AI 도구 사용 가이드라인&quot;">​</a></h3><p><strong>시행일:</strong> 20XX년 XX월 XX일 <strong>적용 대상:</strong> 전 임직원 <strong>관리 부서:</strong> [IT팀 / 경영지원팀]</p><h4 id="_1-목적" tabindex="-1">1. 목적 <a class="header-anchor" href="#_1-목적" aria-label="Permalink to &quot;1. 목적&quot;">​</a></h4><p>본 가이드라인은 임직원의 AI 도구(Claude Desktop Cowork) 사용에 관한 기본 원칙과 주의사항을 정하여, 업무 생산성을 높이면서도 정보 보안과 윤리를 준수하는 것을 목적으로 합니다.</p><h4 id="_2-허용-범위" tabindex="-1">2. 허용 범위 <a class="header-anchor" href="#_2-허용-범위" aria-label="Permalink to &quot;2. 허용 범위&quot;">​</a></h4><p><strong>적극 활용 권장:</strong></p><ul><li>이메일, 보고서, 기획서 등 문서 초안 작성</li><li>맞춤법·문법 교정 및 문서 퇴고</li><li>공개된 데이터 기반 분석 및 요약</li><li>아이디어 브레인스토밍 및 리서치</li><li>회의 내용 정리 및 액션 아이템 도출</li><li>번역 및 다국어 문서 작성</li></ul><p><strong>주의하여 사용:</strong></p><ul><li>사내 비공개 자료 기반 분석 (민감 정보 제거 후 사용)</li><li>고객 관련 업무 (개인정보 비식별화 필수)</li></ul><h4 id="_3-금지-사항" tabindex="-1">3. 금지 사항 <a class="header-anchor" href="#_3-금지-사항" aria-label="Permalink to &quot;3. 금지 사항&quot;">​</a></h4><div class="danger custom-block"><p class="custom-block-title">아래 정보는 절대 입력하지 마세요</p><ul><li>고객·직원 <strong>개인정보</strong> (주민번호, 연락처, 계좌번호 등)</li><li>시스템 <strong>비밀번호, 인증키, API 키</strong></li><li>미공개 <strong>재무 정보</strong> (실적, M&amp;A 관련 등)</li><li><strong>법적 분쟁</strong> 관련 내부 문서 원문</li><li>등급이 &quot;<strong>대외비</strong>&quot; 이상인 문서 원문</li></ul></div><h4 id="_4-사용-원칙" tabindex="-1">4. 사용 원칙 <a class="header-anchor" href="#_4-사용-원칙" aria-label="Permalink to &quot;4. 사용 원칙&quot;">​</a></h4><ol><li><strong>최종 책임은 사람에게</strong> — AI 결과물은 반드시 본인이 검토·수정한 후 사용합니다</li><li><strong>팩트체크 필수</strong> — 수치, 날짜, 고유명사 등 사실 관계는 반드시 원본과 대조합니다</li><li><strong>출처 명시</strong> — AI를 활용한 리서치 결과를 사용할 때는 원출처를 확인합니다</li><li><strong>대외 문서 고지</strong> — AI 활용 사실 고지가 필요한 경우 (계약서, 법률 문서 등) 관련 부서와 협의합니다</li></ol><h4 id="_5-계정-관리" tabindex="-1">5. 계정 관리 <a class="header-anchor" href="#_5-계정-관리" aria-label="Permalink to &quot;5. 계정 관리&quot;">​</a></h4><ul><li>회사 이메일로 가입한 계정만 업무에 사용합니다</li><li>개인 계정으로 업무 데이터를 처리하지 않습니다</li><li>퇴사 시 계정은 IT팀에서 비활성화 처리합니다</li></ul><h4 id="_6-피드백-및-문의" tabindex="-1">6. 피드백 및 문의 <a class="header-anchor" href="#_6-피드백-및-문의" aria-label="Permalink to &quot;6. 피드백 및 문의&quot;">​</a></h4><ul><li>AI 사용 관련 질문: [Slack/Teams 채널명]</li><li>보안 관련 신고: [보안팀 이메일]</li><li>가이드라인 개정 의견: [담당자 이메일]</li></ul><hr><div class="tip custom-block"><p class="custom-block-title">이 가이드라인을 배포할 때</p><ol><li>전 직원 이메일 또는 사내 공지로 안내</li><li>온보딩 교육 시 5분간 핵심 내용 설명</li><li>사내 위키/인트라넷에 상시 열람 가능하도록 게시</li><li>반기 1회 내용 검토 및 업데이트</li></ol></div>`,95)])])}const p=e(r,[["render",s]]);export{u as __pageData,p as default};
